package pe.edu.utp.tmo.service.impl; import org.springframework.security.crypto.password.PasswordEncoder; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import pe.edu.utp.tmo.dao.UsuarioDAO; import pe.edu.utp.tmo.dto.request.UserCreateRequest; import pe.edu.utp.tmo.dto.response.UserResponse; import pe.edu.utp.tmo.exception.ValidacionNegocioException; import pe.edu.utp.tmo.model.entity.Usuario; import pe.edu.utp.tmo.service.UserService; import pe.edu.utp.tmo.util.ValidationUtils; @Service public class UserServiceImpl implements UserService{ private final UsuarioDAO dao; private final PasswordEncoder enc; public UserServiceImpl(UsuarioDAO dao,PasswordEncoder enc){this.dao=dao;this.enc=enc;} @Transactional public UserResponse crear(UserCreateRequest r){String c=ValidationUtils.correo(r.correo()); if(dao.existePorCorreo(c)) throw new ValidacionNegocioException("CORREO_DUPLICADO","Ya existe un usuario con ese correo."); Usuario u=dao.guardar(new Usuario(r.nombres(),c,enc.encode(r.password()),r.rol(),r.area(),true)); return new UserResponse(u.getId(),u.getNombres(),u.getCorreo(),u.getRol().name(),u.getArea(),u.isActivo());}}